export async function createThemePreset(c: any) {
  try {
    if (!await isAdmin(c)) return errRes(c, "Unauthorized", 401);
    const body = await c.req.json();
    const name = typeof body?.name === "string" ? body.name.trim() : "";
    if (!name) return errRes(c, "Nom du preset requis", 400);
    const themePayload = isPlainObject(body?.theme) ? normalizeTheme(body.theme) : null;
    if (!themePayload) return errRes(c, "Theme payload invalide", 400);

    if (await useDB()) {
      const { data, error } = await db
        .from("theme_presets")
        .insert({
          name,
          description: typeof body?.description === "string" ? body.description : "",
          theme: themePayload,
        })
        .select("*")
        .single();
      if (error && !isMissingRelationError(error)) {
        return errRes(c, `Create preset DB error: ${error.message}`, 500);
      }
      if (data) return respond(c, { preset: data });
    }
    return respond(c, { preset: { id: crypto.randomUUID(), name, theme: themePayload, created_at: new Date().toISOString() } });
  } catch (e) {
    return errRes(c, `Create preset error: ${e.message}`);
  }
